  2	import {
  3	  useSafeK8sGet,
  4	  useSafeK8sList,
  5	  useSafeK8sWatchResource,
  6	} from '@odf/core/hooks';
  7	import { useODFSystemFlagsSelector } from '@odf/core/redux';
  8	import { getResourceInNs as getCephClusterInNs } from '@odf/core/utils';
  9	import { CephBlockPoolModel, CephFileSystemModel } from '@odf/shared';
 10	import { StatusBox } from '@odf/shared/generic/status-box';
 11	import { CephClusterModel, StorageClusterModel } from '@odf/shared/models';
 12	import { getName } from '@odf/shared/selectors';
 13	import {
 14	  CephClusterKind,
 15	  DataPool,
 16	  StorageClusterKind,
 17	} from '@odf/shared/types';
 18	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 19	import { referenceForModel } from '@odf/shared/utils';
 20	import {
 21	  K8sResourceCommon,
 22	  Patch,
 23	  WatchK8sResource,
 24	  getAPIVersionForModel,
 25	  k8sCreate,
 26	  k8sPatch,
 27	  useK8sWatchResource,
 28	} from '@openshift-console/dynamic-plugin-sdk';
 29	import { useParams, useNavigate } from 'react-router-dom-v5-compat';
 30	import {
 31	  Button,
 32	  Modal,
 33	  TextContent,
 34	  Text,
 35	  TextVariants,
 36	} from '@patternfly/react-core';
 37	import {
 38	  ADDITIONAL_FS_POOLS_CLUSTER_CR_PATH,
 39	  COMPRESSION_ON,
 40	  PoolState,
 41	  PoolType,
 42	} from '../constants';
 43	import { CephFilesystemKind, StoragePoolKind } from '../types';
 44	import {
 45	  getErrorMessage,
 46	  getExistingBlockPoolNames,
 47	  getExistingFsPoolNames,
 48	} from '../utils';
 49	import { StoragePoolBody } from './body';
 50	import { StoragePoolFooter } from './footer';
 51	import {
 52	  StoragePoolActionType,
 53	  blockPoolInitialState,
 54	  storagePoolReducer,
 55	  StoragePoolState,
 56	} from './reducer';
 57	import './create-storage-pool.scss';
 58	import '../style.scss';
 59	
 60	export const createFsPoolRequest = (
 61	  state: StoragePoolState,
 62	  storageCluster: StorageClusterKind
 63	) => {
 64	  const patchPool: DataPool = {
 65	    name: state.poolName,
 66	    replicated: { size: Number(state.replicaSize) },
 67	    compressionMode: state.isCompressed ? COMPRESSION_ON : 'none',
 68	  };
 69	  const patch: Patch = storageCluster?.spec?.managedResources?.cephFilesystems
 70	    ?.additionalDataPools
 71	    ? {
 72	        op: 'add',
 73	        path: `${ADDITIONAL_FS_POOLS_CLUSTER_CR_PATH}/-`,
 74	        value: patchPool,
 75	      }
 76	    : {
 77	        op: 'add',
 78	        path: ADDITIONAL_FS_POOLS_CLUSTER_CR_PATH,
 79	        value: [patchPool],
 80	      };
 81	
 82	  return () =>
 83	    k8sPatch({
 84	      model: StorageClusterModel,
 85	      resource: storageCluster,
 86	      data: [patch],
 87	    });
 88	};
 89	
 90	export const getPoolKindObj = (
 91	  state: StoragePoolState,
 92	  ns: string,
 93	  deviceClass: StoragePoolKind['spec']['deviceClass']
 94	): StoragePoolKind => ({
 95	  apiVersion: getAPIVersionForModel(CephBlockPoolModel),
 96	  kind: CephBlockPoolModel.kind,
 97	  metadata: {
 98	    name: state.poolName,
 99	    namespace: ns,
100	  },
101	  spec: {
102	    compressionMode: state.isCompressed ? COMPRESSION_ON : 'none',
103	    // without explicit "true" Rook will not allow updating CRUSH Rules ("deviceClass" will not be set)
104	    enableCrushUpdates: true,
105	    deviceClass: deviceClass,
106	    failureDomain: state.failureDomain,
107	    parameters: {
108	      compression_mode: state.isCompressed ? COMPRESSION_ON : 'none',
109	    },
110	    replicated: {
111	      size: Number(state.replicaSize),
112	    },
113	  },
114	});
115	
116	export const cephClusterResource = {
117	  kind: referenceForModel(CephClusterModel),
118	  isList: true,
119	};
120	
121	export const poolResource = (
122	  poolName: string,
123	  ns: string
124	): WatchK8sResource => ({
125	  kind: referenceForModel(CephBlockPoolModel),
126	  namespaced: true,
127	  isList: false,
128	  name: poolName,
129	  namespace: ns,
130	});
131	
132	export const StoragePoolDefinitionText: React.FC<{ className?: string }> = ({
133	  className,
134	}) => {
135	  const { t } = useCustomTranslation();
136	
137	  return (
138	    <p className={className}>
139	      {t(
140	        'A storage pool is a logical entity which provides capacity to applications and workloads. With pools you can support policies for data resiliency and storage efficiency.'
141	      )}
142	    </p>
143	  );
144	};
145	
146	const CreateStoragePool: React.FC<{}> = ({}) => {
147	  const { t } = useCustomTranslation();
148	  const params = useParams();
149	  const poolNs = params?.namespace;
150	
151	  const { systemFlags, areFlagsLoaded, flagsLoadError } =
152	    useODFSystemFlagsSelector();
153	  const clusterName = systemFlags[poolNs]?.ocsClusterName;
154	
155	  const isExternalStorageSystem = systemFlags[poolNs]?.isExternalMode;
156	
157	  // We read pools from CephFilesystem as it's the only resource where the default pool appears
158	  // (unlike in StorageCluster CR).
159	  const fsName = `${clusterName}-cephfilesystem`;
160	  const [fsData, fsDataLoaded, fsDataLoadError] =
161	    useSafeK8sWatchResource<CephFilesystemKind>((ns) => ({
162	      isList: false,
163	      kind: referenceForModel(CephFileSystemModel),
164	      namespaced: true,
165	      namespace: ns,
166	      name: fsName,
167	    }));
168	
169	  // Collect existing fs pool names to check against new pool name.
170	  const fsExistingNames = React.useMemo(
171	    () => getExistingFsPoolNames(fsData),
172	    [fsData]
173	  );
174	
175	  const [cephClusters, cephClustersLoaded, cephClustersLoadError] =
176	    useK8sWatchResource<CephClusterKind[]>(cephClusterResource);
177	  // Only single cluster per Namespace.
178	  const cephCluster = getCephClusterInNs(
179	    cephClusters,
180	    poolNs
181	  ) as CephClusterKind;
182	
183	  // Collect existing block pool names to check against new pool name.
184	  // Also get the block default deviceClass.
185	  const defaultBlockPoolName = `${clusterName}-cephblockpool`;
186	  const [blockPools, blockPoolsLoaded, blockPoolsLoadError] =
187	    useSafeK8sList<StoragePoolKind>(CephBlockPoolModel);
188	
189	  const [blockExistingNames, defaultDeviceClass] = React.useMemo(() => {
190	    let blockPoolNames = [];
191	    let defaultDeviceClass = '';
192	    if (blockPoolsLoaded && !blockPoolsLoadError) {
193	      blockPoolNames = getExistingBlockPoolNames(blockPools);
194	      defaultDeviceClass =
195	        blockPools.find(
196	          (blockPool) => getName(blockPool) === defaultBlockPoolName
197	        )?.spec?.deviceClass || '';
198	    }
199	
200	    return [blockPoolNames, defaultDeviceClass];
201	  }, [blockPools, blockPoolsLoaded, blockPoolsLoadError, defaultBlockPoolName]);
202	
203	  const [storageCluster, storageClusterLoaded, storageClusterLoadError] =
204	    useSafeK8sGet<StorageClusterKind>(StorageClusterModel, clusterName, poolNs);
205	
206	  const isLoaded =
207	    areFlagsLoaded &&
208	    fsDataLoaded &&
209	    cephClustersLoaded &&
210	    storageClusterLoaded &&
211	    blockPoolsLoaded;
212	  const isLoadError =
213	    flagsLoadError ||
214	    fsDataLoadError ||
215	    cephClustersLoadError ||
216	    storageClusterLoadError ||
217	    blockPoolsLoadError;
218	
219	  if (isLoaded && !isLoadError) {
220	    return (
221	      <CreateStoragePoolForm
222	        appName={params.appName}
223	        storageCluster={storageCluster}
224	        cephCluster={cephCluster}
225	        isExternalStorageSystem={isExternalStorageSystem}
226	        poolNs={poolNs}
227	        fsName={fsName}
228	        fsExistingNames={fsExistingNames}
229	        blockExistingNames={blockExistingNames}
230	        defaultDeviceClass={defaultDeviceClass}
231	      />
232	    );
233	  }
234	  return (
235	    <StatusBox
236	      loaded={isLoaded}
237	      loadError={isLoadError}
238	      label={t('Storage pool creation form')}
239	    />
240	  );
241	};
242	
243	type CreateStoragePoolFormProps = {
244	  appName: string;
245	  storageCluster: StorageClusterKind;
246	  cephCluster: CephClusterKind;
247	  isExternalStorageSystem: boolean;
248	  poolNs: string;
249	  fsName: string;
250	  fsExistingNames: string[];
251	  blockExistingNames: string[];
252	  defaultDeviceClass: string;
253	};
254	
255	const CreateStoragePoolForm: React.FC<CreateStoragePoolFormProps> = ({
256	  storageCluster,
257	  cephCluster,
258	  isExternalStorageSystem,
259	  poolNs,
260	  fsName,
261	  fsExistingNames,
262	  blockExistingNames,
263	  defaultDeviceClass,
264	}) => {
265	  const { t } = useCustomTranslation();
266	  const navigate = useNavigate();
267	
268	  const [state, dispatch] = React.useReducer(
269	    storagePoolReducer,
270	    blockPoolInitialState
271	  );
272	  const [poolType, setPoolType] = React.useState<PoolType>(PoolType.FILESYSTEM);
273	  const onPoolTypeChange = React.useMemo(
274	    () => (newPoolType: PoolType) => setPoolType(newPoolType),
275	    [setPoolType]
276	  );
277	  const existingNames =
278	    poolType === PoolType.FILESYSTEM ? fsExistingNames : blockExistingNames;
279	
280	  const blockPoolPageUrl = '/odf/storage-cluster/storage-pools';
281	
282	  const onClose = () => {
283	    navigate(-1);
284	  };
285	
286	  // Create new pool
287	  const createPool = () => {
288	    if (cephCluster?.status?.phase === PoolState.READY) {
289	      let createRequest: () => Promise<K8sResourceCommon>;
290	      if (poolType === PoolType.FILESYSTEM) {
291	        createRequest = createFsPoolRequest(state, storageCluster);
292	      } else {
293	        const poolObj: StoragePoolKind = getPoolKindObj(
294	          state,
295	          poolNs,
296	          defaultDeviceClass
297	        );
298	        createRequest = () =>
299	          k8sCreate({ model: CephBlockPoolModel, data: poolObj });
300	      }
301	
302	      dispatch({ type: StoragePoolActionType.SET_INPROGRESS, payload: true });
303	      createRequest()
304	        .then(() =>
305	          poolType === PoolType.BLOCK
306	            ? navigate(
307	                `${blockPoolPageUrl}/${state.poolName}?namespace=${poolNs}`
308	              )
309	            : navigate(`${blockPoolPageUrl}`)
310	        )
311	        .finally(() =>
312	          dispatch({
313	            type: StoragePoolActionType.SET_INPROGRESS,
314	            payload: false,
315	          })
316	        )
317	        .catch((err) =>
318	          dispatch({
319	            type: StoragePoolActionType.SET_ERROR_MESSAGE,
320	            payload: getErrorMessage(err.message) || 'Could not create Pool.',
321	          })
322	        );
323	    } else
324	      dispatch({
325	        type: StoragePoolActionType.SET_ERROR_MESSAGE,
326	        payload: t(
327	          "Data Foundation's StorageCluster is not available. Try again after the StorageCluster is ready to use."
328	        ),
329	      });
330	  };
331	
332	  if (isExternalStorageSystem) {
333	    return (
334	      <Modal
335	        title={t('Create storage pool')}
336	        titleIconVariant="warning"
337	        isOpen
338	        onClose={onClose}
339	        variant="small"
340	        actions={[
341	          <Button key="confirm" variant="primary" onClick={onClose}>
342	            {t('Close')}
343	          </Button>,
344	        ]}
345	      >
346	        <strong>
347	          {t(
348	            "Pool creation is not supported for Data Foundation's external RHCS storage system."
349	          )}
350	        </strong>
351	      </Modal>
352	    );
353	  }
354	
355	  return (
356	    <>
357	      <div className="odf-create-operand__header">
358	        <TextContent className="odf-create-operand__header-text">
359	          <Text component={TextVariants.h1}>{t('Create storage pool')}</Text>
360	        </TextContent>
361	        <StoragePoolDefinitionText />
362	      </div>
363	      <div className="create-storage-pool__form">
364	        <StoragePoolBody
365	          cephCluster={cephCluster}
366	          state={state}
367	          dispatch={dispatch}
368	          showPoolStatus={false}
369	          poolType={poolType}
370	          existingNames={existingNames}
371	          onPoolTypeChange={onPoolTypeChange}
372	          prefixName={fsName}
373	        />
374	        <StoragePoolFooter
375	          state={state}
376	          cancel={onClose}
377	          onConfirm={createPool}
378	        />
379	      </div>
380	    </>
381	  );
382	};
383	
384	export default CreateStoragePool;

