205	  const [storageCluster, storageClusterLoaded, storageClusterLoadError] =
206	    useSafeK8sGet<StorageClusterKind>(StorageClusterModel, clusterName, poolNs);
207	
208	  const isLoaded =
209	    areFlagsLoaded &&
210	    fsDataLoaded &&
211	    cephClustersLoaded &&
212	    storageClusterLoaded &&
213	    blockPoolsLoaded;
214	  const isLoadError =
215	    flagsLoadError ||
216	    fsDataLoadError ||
217	    cephClustersLoadError ||
218	    storageClusterLoadError ||
219	    blockPoolsLoadError;
220	
221	  if (isLoaded && !isLoadError) {
222	    return (
