243	};
244	
245	type CreateStoragePoolFormProps = {
246	  appName: string;
247	  storageCluster: StorageClusterKind;
248	  cephCluster: CephClusterKind;
249	  isExternalStorageSystem: boolean;
250	  poolNs: string;
251	  fsName: string;
