248	  cephCluster: CephClusterKind;
249	  isExternalStorageSystem: boolean;
250	  poolNs: string;
251	  fsName: string;
252	  fsExistingNames: string[];
253	  blockExistingNames: string[];
254	  defaultDeviceClass: string;
255	};
256	
257	const CreateStoragePoolForm: React.FC<CreateStoragePoolFormProps> = ({
258	  storageCluster,
259	  cephCluster,
260	  isExternalStorageSystem,
261	  poolNs,
262	  fsName,
263	  fsExistingNames,
264	  blockExistingNames,
265	  defaultDeviceClass,
266	}) => {
267	  const { t } = useCustomTranslation();
268	  const navigate = useNavigate();
269	
270	  const [state, dispatch] = React.useReducer(
271	    storagePoolReducer,
272	    blockPoolInitialState
273	  );
274	  const [poolType, setPoolType] = React.useState<PoolType>(PoolType.FILESYSTEM);
275	  const onPoolTypeChange = React.useMemo(
276	    () => (newPoolType: PoolType) => setPoolType(newPoolType),
277	    [setPoolType]
278	  );
279	  const existingNames =
280	    poolType === PoolType.FILESYSTEM ? fsExistingNames : blockExistingNames;
281	
282	  const blockPoolPageUrl = '/odf/storage-cluster/storage-pools';
283	
284	  const onClose = () => {
285	    navigate(-1);
286	  };
287	
288	  // Create new pool
289	  const createPool = () => {
290	    if (cephCluster?.status?.phase === PoolState.READY) {
291	      let createRequest: () => Promise<K8sResourceCommon>;
292	      if (poolType === PoolType.FILESYSTEM) {
293	        createRequest = createFsPoolRequest(state, storageCluster);
294	      } else {
295	        const poolObj: StoragePoolKind = getPoolKindObj(
296	          state,
297	          poolNs,
298	          defaultDeviceClass
299	        );
300	        createRequest = () =>
301	          k8sCreate({ model: CephBlockPoolModel, data: poolObj });
302	      }
303	
304	      dispatch({ type: StoragePoolActionType.SET_INPROGRESS, payload: true });
305	      createRequest()
306	        .then(() =>
307	          poolType === PoolType.BLOCK
308	            ? navigate(
309	                `${blockPoolPageUrl}/${state.poolName}?namespace=${poolNs}`
310	              )
311	            : navigate(`${blockPoolPageUrl}`)
312	        )
313	        .finally(() =>
314	          dispatch({
315	            type: StoragePoolActionType.SET_INPROGRESS,
316	            payload: false,
317	          })
318	        )
319	        .catch((err) =>
320	          dispatch({
321	            type: StoragePoolActionType.SET_ERROR_MESSAGE,
322	            payload: getErrorMessage(err.message) || 'Could not create Pool.',
323	          })
324	        );
325	    } else
326	      dispatch({
327	        type: StoragePoolActionType.SET_ERROR_MESSAGE,
328	        payload: t(
329	          "Data Foundation's StorageCluster is not available. Try again after the StorageCluster is ready to use."
330	        ),
331	      });
332	  };
333	
334	  if (isExternalStorageSystem) {
335	    return (
336	      <Modal
337	        isOpen
338	        onClose={onClose}
339	        variant="small"
340	      >
341	        <ModalHeader title={t('Create storage pool')} titleIconVariant="warning" />
342	        <ModalBody>
343	          <strong>
344	            {t(
345	              "Pool creation is not supported for Data Foundation's external RHCS storage system."
346	            )}
347	          </strong>
348	        </ModalBody>
349	        <ModalFooter>
350	          <Button key="confirm" variant="primary" onClick={onClose}>
351	            {t('Close')}
352	          </Button>
353	        </ModalFooter>
354	      </Modal>
355	    );
356	  }
357	
358	  return (
359	    <>
360	      <div className="odf-create-operand__header">
361	        <Content className="odf-create-operand__header-text" component={ContentVariants.h1}>
362	          {t('Create storage pool')}
363	        </Content>
364	        <StoragePoolDefinitionText />
365	      </div>
366	      <div className="create-storage-pool__form">
367	        <StoragePoolBody
368	          cephCluster={cephCluster}
369	          state={state}
370	          dispatch={dispatch}
371	          showPoolStatus={false}
372	          poolType={poolType}
373	          existingNames={existingNames}
374	          onPoolTypeChange={onPoolTypeChange}
375	          prefixName={fsName}
376	        />
377	        <StoragePoolFooter
378	          state={state}
379	          cancel={onClose}
380	          onConfirm={createPool}
381	        />
382	      </div>
383	    </>
384	  );
385	};
386	
387	export default CreateStoragePool;
